mapper.select:
SELECT ocbr.*,oc.oil_card_no oilCardNo
FROM t_oil_card_balance_record ocbr
LEFT JOIN t_oil_card oc on oc.oil_card_id = ocbr.oil_card_id


       AND ocbr.oil_card_id = #{queryForm.oilCardId}


        AND (INSTR(ocbr.balance_record_no,#{queryForm.keyWords})
        or INSTR(ocbr.create_user_name,#{queryForm.keyWords})
        )


        AND ocbr.record_type = #{queryForm.type}


        AND ocbr.record_type in

            #{item}




        and DATE_FORMAT(ocbr.create_time, '%Y-%m-%d') >= #{queryForm.startTime}


        and DATE_FORMAT(ocbr.create_time, '%Y-%m-%d') <= #{queryForm.endTime}




    ORDER BY ocbr.create_time DESC

SELECT oil_card_id,
SUM( change_balance ) balance
FROM t_oil_card_balance_record
where oil_card_id in

    #{item}

AND record_type = #{recordType}

    and DATE_FORMAT(transaction_time, '%Y-%m-%d') >= #{startTime}


    and DATE_FORMAT(transaction_time, '%Y-%m-%d') <= #{endTime}

group by oil_card_id
